import { env } from "cloudflare:workers";
import { TodoList } from "./TodoList";
import type { Todo } from "../actions";

export const Home = async () => {
  const list = await env.TODOS.list({ prefix: "todo:" });
  const todos: Todo[] = [];

  for (const key of list.keys) {
    const value = await env.TODOS.get(key.name);
    if (value) {
      todos.push(JSON.parse(value));
    }
  }

  todos.sort((a, b) => a.createdAt - b.createdAt);
  const remaining = todos.filter((t) => !t.done).length;

  return <TodoList todos={todos} remaining={remaining} />;
};

import { render, route } from "rwsdk/router";
import { defineApp } from "rwsdk/worker";
import { env } from "cloudflare:workers";

import { Document } from "@/app/document";
import { setCommonHeaders } from "@/app/headers";
import { Home } from "@/app/pages/home";

export type AppContext = {};

export default defineApp([
  setCommonHeaders(),
  ({ ctx }) => {
    ctx;
  },
  route("/api/todos", {
    get: async () => {
      const list = await env.TODOS.list({ prefix: "todo:" });
      const todos = [];

      for (const key of list.keys) {
        const value = await env.TODOS.get(key.name);
        if (value) {
          todos.push(JSON.parse(value));
        }
      }

      todos.sort((a: { createdAt: number }, b: { createdAt: number }) => a.createdAt - b.createdAt);
      const remaining = todos.filter((t: { done: boolean }) => !t.done).length;

      return Response.json({ todos, remaining });
    },
  }),
  render(Document, [route("/", Home)]),
]);

import { defineConfig } from "vite";
import { redwood } from "rwsdk/vite";
import { cloudflare } from "@cloudflare/vite-plugin";

export default defineConfig({
  plugins: [
    cloudflare({
      viteEnvironment: { name: "worker" },
    }),
    redwood(),
  ],
});

"use client";

import { addTodo, toggleTodo, deleteTodo } from "../actions";
import type { Todo } from "../actions";

export function TodoList({
  todos,
  remaining,
}: {
  todos: Todo[];
  remaining: number;
}) {
  return (
    <div style={{ maxWidth: 600, margin: "0 auto", padding: 20 }}>
      <h1>Todos</h1>

      <form action={addTodo} style={{ marginBottom: 20 }}>
        <input
          type="text"
          name="title"
          aria-label="New todo title"
          required
          style={{ padding: "8px 12px", fontSize: 16 }}
        />
        <button type="submit" style={{ padding: "8px 16px", fontSize: 16 }}>
          Add
        </button>
      </form>

      {todos.length === 0 && <p>No todos yet. Add one above!</p>}

      <ul style={{ listStyle: "none", padding: 0 }}>
        {todos.map((todo) => (
          <li
            key={`${todo.id}-${todo.done}`}
            data-done={todo.done ? "true" : "false"}
            style={{
              display: "flex",
              alignItems: "center",
              gap: 8,
              padding: "8px 0",
              borderBottom: "1px solid #eee",
            }}
          >
            <form action={toggleTodo} style={{ display: "inline", margin: 0 }}>
              <input type="hidden" name="id" value={todo.id} />
              <input
                type="checkbox"
                name="done"
                aria-label={`Toggle ${todo.title}`}
                defaultChecked={todo.done}
                onChange={(e) => e.target.form?.requestSubmit()}
              />
            </form>
            <span
              data-testid="todo-title"
              style={{
                flex: 1,
                textDecoration: todo.done ? "line-through" : "none",
                color: todo.done ? "#999" : "#000",
              }}
            >
              {todo.title}
            </span>
            <form action={deleteTodo} style={{ display: "inline", margin: 0 }}>
              <input type="hidden" name="id" value={todo.id} />
              <button
                type="submit"
                aria-label={`Delete ${todo.title}`}
                style={{ padding: "4px 8px" }}
              >
                Delete
              </button>
            </form>
          </li>
        ))}
      </ul>

      <p data-testid="remaining-count">{remaining} item{remaining !== 1 ? "s" : ""} remaining</p>
    </div>
  );
}
